import gradio as gr
import pandas as pd
import numpy as np

def process_data(input_text):
    return f"Processed: {input_text}"

demo = gr.Interface(
    fn=process_data,
    inputs="text",
    outputs="text",
    title="My Gradio App"
)

if __name__ == "__main__":
    demo.launch()
